    Evaluate a tiny arithmetic expression language with explicit resource bounds.

    Args:
        expression: String containing the arithmetic expression
        variables: Dictionary mapping variable names to integer values
        max_nodes: Maximum allowed AST nodes (default: 32)

    Returns:
        Integer result of evaluating the expression

    Raises:
        ValueError: If expression violates any constraints
    """
    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")

    # Count nodes and validate structure
    node_count = count_nodes(tree)
    if node_count > max_nodes:
        raise ValueError(f"Expression exceeds maximum node count: {node_count} > {max_nodes}")

    # Validate AST structure
    validate_ast(tree.body, variables)

    # Evaluate the expression
    return evaluate_node(tree.body, variables)

def count_nodes(node: ast.AST) -> int:
    """Count all AST nodes recursively."""
    count = 1  # Count this node
    for field in ast.iter_fields(node):
        value = field[1]
        if isinstance(value, list):
            for item in value:
                if isinstance(item, ast.AST):
                    count += count_nodes(item)
        elif isinstance(value, ast.AST):
            count += count_nodes(value)
    return count

def validate_ast(node: ast.AST, variables: dict[str, int]) -> None:
    """
    Validate that the AST only contains allowed constructs.

    Allowed:
    - Constant (integers only)
    - Name (variables only, must be in variables dict)
    - UnaryOp with USub (unary minus)
    - BinOp with Add, Sub, Mult, FloorDiv
    - Expression (top-level wrapper)

    Raises ValueError if any disallowed construct is found.
    """
