        validate_ast(node.body, variables)

    elif isinstance(node, ast.Constant):
        if not isinstance(node.value, int):
            raise ValueError(f"Only integer constants are allowed, got {type(node.value).__name__}")

    elif isinstance(node, ast.Name):
        if node.id not in variables:
            raise ValueError(f"Unknown variable: {node.id}")

    elif isinstance(node, ast.UnaryOp):
        if not isinstance(node.op, ast.USub):
            raise ValueError(f"Only unary minus is allowed, got {type(node.op).__name__}")
        validate_ast(node.operand, variables)

    elif isinstance(node, ast.BinOp):
        # Validate operator
        allowed_ops = {ast.Add, ast.Sub, ast.Mult, ast.FloorDiv}
        if type(node.op) not in allowed_ops:
            raise ValueError(f"Disallowed binary operator: {type(node.op).__name__}")

        # Validate operands
        validate_ast(node.left, variables)
        validate_ast(node.right, variables)

    else:
        raise ValueError(f"Disallowed AST node type: {type(node).__name__}")

def evaluate_node(node: ast.AST, variables: dict[str, int]) -> int:
    """Evaluate an AST node recursively."""
    if isinstance(node, ast.Expression):
        return evaluate_node(node.body, variables)

    elif isinstance(node, ast.Constant):
        return node.value

    elif isinstance(node, ast.Name):
        return variables[node.id]

    elif isinstance(node, ast.UnaryOp):
        operand_value = evaluate_node(node.operand, variables)
        return -operand_value

    elif isinstance(node, ast.BinOp):
        left_value = evaluate_node(node.left, variables)
        right_value = evaluate_node(node.right, variables)

        # Map AST operators to Python operators
        op_map = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.FloorDiv: operator.floordiv
        }

